/**
 * Pre-rendered watermark bitmap ("Symulacja poglądowa · Mikrostomart").
 *
 * Vercel lambdas have no fonts/fontconfig, so SVG <text> rendered by librsvg
 * comes out as tofu boxes in production. The text is therefore rendered ONCE
 * locally (where fonts exist) into a transparent PNG (white text + soft dark
 * shadow baked in) and embedded here as base64 — zero runtime font
 * dependencies, no file-tracing concerns.
 *
 * Master size: 1566x97px. Regenerate with
 * scratchpad gen_watermark.mjs if the text ever changes.
 */
export const WATERMARK_PNG_BASE64 =
    '';

export const WATERMARK_ASPECT = 16.1443; // width / height
